CREATE TABLE patients (
    patient_id INT AUTO_INCREMENT,
    first_name VARCHAR(100),
    last_name VARCHAR(100),
    date_of_birth DATE,
    gender VARCHAR(11),
    phone_number VARCHAR(15),
    aadhar_number VARCHAR(12),
    email VARCHAR(100),
    city VARCHAR(50),
    district VARCHAR(50),
    state VARCHAR(50),
    country VARCHAR(50),
    blood_group VARCHAR(5),
    bmi DECIMAL(4 , 2 ),
    family_history_cancer BOOLEAN DEFAULT FALSE,
    lifestyle_factor VARCHAR(20),
    registration_date DATE,
    CONSTRAINT pa_patient_id_pk PRIMARY KEY (patient_id),
    CONSTRAINT pa_gender_ck CHECK (gender IN ('Male' , 'Female', 'Other')),
    CONSTRAINT pa_aadhar_number_uk UNIQUE (aadhar_number),
    CONSTRAINT pa_blood_group_ck CHECK (blood_group IN ('A+' , 'A-','B+','B-','AB+','AB-','O+','O-')),
    CONSTRAINT pa_lifestyle_factor_ck CHECK (lifestyle_factor IN ('smoking' , 'alcohol', 'both', 'none'))
);

SELECT 
    *
FROM
    patients;

